}","language":"typescript"},"narration":"At the Normalization Pass, chaos becomes order. Every messaging platform has its own format. The ChannelPlugin interface forces them all into one shape. The gateway never needs to know whether you messaged from WhatsApp or Telegram."},{"name":"Route Resolution Fork","subtitle":"Finding the Right Agent","concept":"Route Resolution","landmarkType":"mountain","code":{"file":"src/routing/resolve-route.ts","content":"// src/routing/resolve-route.ts (simplified)
export function resolveAgentRoute(
  input: ResolveAgentRouteInput
): ResolvedAgentRoute {
  const { cfg, channel, accountId, peer,
          parentPeer, guildId, teamId, memberRoleIds } = input

  // Tiered binding resolution — first match wins
  const tiers = [
    { matchedBy: 'binding.peer',         // 1. Exact peer
      candidates: collectPeerBindings(peer) },
    { matchedBy: 'binding.peer.parent',   // 2. Parent peer (threads)
      candidates: collectPeerBindings(parentPeer) },
    { matchedBy: 'binding.guild+roles',   // 3. Guild + role
      candidates: guildRoleBindings(guildId, memberRoleIds) },
    { matchedBy: 'binding.guild',         // 4. Guild/server
      candidates: guildBindings(guildId) },
    { matchedBy: 'binding.team',          // 5. Team
      candidates: teamBindings(teamId) },
    { matchedBy: 'binding.account',       // 6. Account
      candidates: accountBindings },
    { matchedBy: 'binding.channel',       // 7. Channel wildcard
      candidates: channelBindings },
