    ctx.fillRect(0, 0, W, 110);
    // Snowflakes
    ctx.fillStyle = '#FFFFFF';
    for (var i = 0; i < 50; i++) {
      var sx = (i * 6.7 + t * 30 + Math.sin(t + i) * 10) % W;
