    ctx.fillRect(mx - 1, my - 4, 2, 5);
    ctx.fillRect(mx + 3, my - 4, 2, 5);
    // Hat (cartographer)
    ctx.fillStyle = '#553311';
    ctx.fillRect(mx - 2, my - 17, 8, 2);
    ctx.fillRect(mx - 1, my - 19, 6, 2);
