// ============================================================
// HUD
// ============================================================
const hud = document.getElementById('hud');
const hudName = hud.querySelector('.trail-name');
const hudSub = hud.querySelector('.trail-sub');
const hudNum = hud.querySelector('.disk-number');
const dotsEl = document.getElementById('dots');
const prevBtn = document.getElementById('prev-btn');
const nextBtn = document.getElementById('next-btn');
const playBtn = document.getElementById('play-btn');

// Build dots
TRAILS.forEach((_, i) => {
  const dot = document.createElement('div');
  dot.className = 'dot' + (i === 0 ? ' active' : '');
  dotsEl.appendChild(dot);
});
const dots = dotsEl.querySelectorAll('.dot');

function updateHUD(idx) {
  const t = TRAILS[idx];
  hudName.textContent = t.name;
  hudName.style.color = t.color === '#F7DF1E' ? '#FFE066' : (t.color === '#8B95A2' ? '#C8D0DC' : t.color);
  hudSub.textContent = t.subtitle;
  hudNum.textContent = `DISK ${idx + 1} OF ${TRAILS.length}`;
  dots.forEach((d, i) => d.classList.toggle('active', i === idx));
}

// ============================================================
// SCENE SETUP
// ============================================================
const canvas = document.getElementById('scene');
let renderer, scene, camera;

try {
  renderer = new THREE.WebGLRenderer({ canvas, antialias: true });
} catch (e) {
  document.getElementById('fallback').style.display = 'flex';
  canvas.style.display = 'none';
  hud.style.display = 'none';
  throw e;
}

renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.6;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;

scene = new THREE.Scene();
scene.background = new THREE.Color('#2a2520');

camera = new THREE.PerspectiveCamera(36, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0.0, 3.0, 6.0);
camera.lookAt(0.0, 0.7, 0);

window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});

// Reset fully if restored from bfcache (back button after navigation)
window.addEventListener('pageshow', (e) => { if (e.persisted) location.reload(); });

// ============================================================
// LIGHTING
// ============================================================
// Bright ambient — well-lit room like the reference photo
const ambientLight = new THREE.AmbientLight('#e8e0d0', 1.0);
scene.add(ambientLight);

// Warm key light from brass desk lamp
const deskLamp = new THREE.SpotLight('#FFD080', 60, 14, Math.PI / 3.5, 0.5, 1.0);
deskLamp.position.set(2.8, 3.8, 1.5);
deskLamp.target.position.set(0, 0.3, 0.5);
deskLamp.castShadow = true;
deskLamp.shadow.mapSize.set(1024, 1024);

