700	// TWEEN SYSTEM
701	// ============================================================
702	const tweens = [];
703	function easeInOutCubic(t) { return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2; }
704	
705	class Tween {
706	  constructor(target, prop, from, to, duration, ease = easeInOutCubic, delay = 0) {
707	    this.target = target; this.prop = prop; this.from = from; this.to = to;
708	    this.duration = duration; this.ease = ease; this.elapsed = -delay;
709	    this.done = false; this.onComplete = null;
710	  }
711	  update(dt) {
712	    if (this.done) return true;
713	    this.elapsed += dt;
714	    if (this.elapsed < 0) return false;
715	    const t = Math.min(this.elapsed / this.duration, 1);
716	    this.target[this.prop] = this.from + (this.to - this.from) * this.ease(t);
717	    if (t >= 1) { this.done = true; if (this.onComplete) this.onComplete(); return true; }
718	    return false;
