// TWEEN SYSTEM
// ============================================================
const tweens = [];
function easeInOutCubic(t) { return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2; }

class Tween {
  constructor(target, prop, from, to, duration, ease = easeInOutCubic, delay = 0) {
    this.target = target; this.prop = prop; this.from = from; this.to = to;
    this.duration = duration; this.ease = ease; this.elapsed = -delay;
    this.done = false; this.onComplete = null;
  }
  update(dt) {
    if (this.done) return true;
    this.elapsed += dt;
    if (this.elapsed < 0) return false;
    const t = Math.min(this.elapsed / this.duration, 1);
    this.target[this.prop] = this.from + (this.to - this.from) * this.ease(t);
    if (t >= 1) { this.done = true; if (this.onComplete) this.onComplete(); return true; }
    return false;
  }
}

function addTween(target, prop, from, to, dur, ease, delay) {
  const tw = new Tween(target, prop, from, to, dur, ease, delay);
  tweens.push(tw); return tw;
}

