node -e "
const fs = require('fs');
const html = fs.readFileSync('index.html', 'utf8');
const scriptMatch = html.match(/<script type=\"module\">([\s\S]*?)<\/script>/);
if (scriptMatch) {
  // Check for balanced braces
  const code = scriptMatch[1];
  let depth = 0;
  for (const ch of code) {
    if (ch === '{') depth++;
    if (ch === '}') depth--;
  }
  console.log('Brace balance:', depth === 0 ? 'OK' : 'MISMATCH (depth=' + depth + ')');
  console.log('Lines:', code.split('\n').length);
  console.log('Has switchCategory:', code.includes('switchCategory'));
  console.log('Has filterTrails:', code.includes('filterTrails'));
  console.log('Has rebuildDots:', code.includes('rebuildDots'));
}
"
